export * from './radio.component';
export * from './radio-group.component';
export * from './radio-card.component';
export * from './radio.base';
export * from './radio.variants';
export * from './radio.token';
export * from './radio.imports';

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '{{alias}}/utils';
import { HbRadioBase } from './radio.base';
import { radioCardVariants, radioVariants } from './radio.variants';

@Component({
  selector: 'hb-radio-card',
  template: `
    <label [class]="cardClasses()" [attr.data-state]="state()" [attr.aria-invalid]="isInvalid() || null">
      <input
        type="radio"
        class="peer sr-only"
        [id]="hbInputId() || uid"
        [name]="name()"
        [value]="stringValue()"
        [checked]="checked()"
        [disabled]="isDisabled()"
        [attr.aria-invalid]="isInvalid() || null"
        (change)="onSelect()"
        (blur)="onTouched()"
      />
      <div class="flex-1"><ng-content /></div>
      @if (hbIndicator()) {
        <span
          [class]="circleClasses()"
          [attr.data-state]="state()"
          aria-hidden="true"
        >
          @if (checked()) {
            <span data-slot="radio-dot"></span>
          }
        </span>
      }
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': "'block'", '[attr.data-slot]': "'radio-card'" },
  exportAs: 'hbRadioCard',
})
export class HbRadioCardComponent extends HbRadioBase {
  readonly hbIndicator = input(true, { transform: booleanAttribute });

  protected readonly cardClasses = computed(() =>
    cn(radioCardVariants({ status: this.effStatus() }), this.class()),
  );
  protected readonly circleClasses = computed(() =>
    cn(radioVariants({ size: this.effSize(), status: this.effStatus(), focusable: false })),
  );
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_RADIO_GROUP, type HbRadioGroupContext } from './radio.token';
import { type HbRadioSize, type HbRadioStatus } from './radio.variants';



let radioGroupUid = 0;
@Component({
  selector: 'hb-radio-group',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    { provide: NG_VALUE_ACCESSOR, useExisting: forwardRef(() => HbRadioGroupComponent), multi: true },
    { provide: HB_RADIO_GROUP, useExisting: forwardRef(() => HbRadioGroupComponent) },
  ],
  host: {
    '[class]': 'classes()',
    role: 'radiogroup',
    '[attr.aria-invalid]': 'hbInvalid() || null',
    '[attr.data-slot]': "'radio-group'",
  },
  exportAs: 'hbRadioGroup',
})
export class HbRadioGroupComponent implements ControlValueAccessor, HbRadioGroupContext {
  readonly hbValue = model<unknown>(null);
  readonly hbName = input<string>('');
  readonly hbOrientation = input<'vertical' | 'horizontal'>('vertical');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbSize = input<HbRadioSize>('md');
  readonly hbStatus = input<HbRadioStatus>('default');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<unknown>();

  private readonly autoName = `hb-radio-group-${++radioGroupUid}`;
  private readonly cvaDisabled = signal(false);

  protected readonly classes = computed(() =>
    cn(
      'flex gap-3',
      this.hbOrientation() === 'horizontal' ? 'flex-row flex-wrap gap-4' : 'flex-col',
      this.class(),
    ),
  );

  value = (): unknown => this.hbValue();
  name = (): string => this.hbName() || this.autoName;
  disabled = (): boolean => this.hbDisabled() || this.cvaDisabled();
  invalid = (): boolean => this.hbInvalid();
  size = (): HbRadioSize => this.hbSize();
  status = (): HbRadioStatus => this.hbStatus();
  isSelected(value: unknown): boolean {
    return this.hbValue() === value;
  }
  select(value: unknown): void {
    this.hbValue.set(value);
    this.onChange(value);
    this.onTouched();
    this.hbChange.emit(value);
  }
  markTouched(): void {
    this.onTouched();
  }

  protected onChange: (value: unknown) => void = () => {};
  protected onTouched: () => void = () => {};
  writeValue(value: unknown): void {
    this.hbValue.set(value);
  }
  registerOnChange(fn: (value: unknown) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import {
  booleanAttribute,
  computed,
  Directive,
  inject,
  input,
  output,
} from '@angular/core';

import { type ClassValue } from '{{alias}}/utils';
import { HB_RADIO_GROUP, type HbRadioGroupContext } from './radio.token';
import { type HbRadioSize, type HbRadioStatus } from './radio.variants';



let radioUid = 0;
@Directive()
export abstract class HbRadioBase {
  protected readonly group = inject<HbRadioGroupContext | null>(HB_RADIO_GROUP, { optional: true });
  protected readonly uid = `hb-radio-${++radioUid}`;

  readonly hbValue = input<unknown>(null);
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbSize = input<HbRadioSize | null>(null);
  readonly hbStatus = input<HbRadioStatus | null>(null);
  readonly hbInputId = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<unknown>();

  protected readonly checked = computed(() =>
    this.group ? this.group.isSelected(this.hbValue()) : false,
  );
  protected readonly isDisabled = computed(
    () => this.hbDisabled() || (this.group?.disabled() ?? false),
  );
  protected readonly isInvalid = computed(
    () => this.hbInvalid() || (this.group?.invalid() ?? false),
  );
  protected readonly effSize = computed<HbRadioSize>(
    () => this.hbSize() ?? this.group?.size() ?? 'md',
  );
  protected readonly effStatus = computed<HbRadioStatus>(
    () => this.hbStatus() ?? this.group?.status() ?? 'default',
  );
  protected readonly state = computed(() => (this.checked() ? 'checked' : 'unchecked'));
  protected readonly name = computed(() => this.group?.name() ?? this.uid);
  protected readonly stringValue = computed(() => {
    const value = this.hbValue();
    return value === null || value === undefined ? null : String(value);
  });

  protected onSelect(): void {
    this.group?.select(this.hbValue());
    this.hbChange.emit(this.hbValue());
  }
  protected onTouched(): void {
    this.group?.markTouched();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '{{alias}}/utils';
import { HbRadioBase } from './radio.base';
import { radioVariants } from './radio.variants';

@Component({
  selector: 'hb-radio',
  template: `
    <label [class]="labelClasses()">
      <input
        type="radio"
        class="peer sr-only"
        [id]="hbInputId() || uid"
        [name]="name()"
        [value]="stringValue()"
        [checked]="checked()"
        [disabled]="isDisabled()"
        [attr.aria-invalid]="isInvalid() || null"
        (change)="onSelect()"
        (blur)="onTouched()"
      />
      <span
        [class]="circleClasses()"
        [attr.data-state]="state()"
        [attr.aria-invalid]="isInvalid() || null"
        aria-hidden="true"
      >
        @if (checked()) {
          <span data-slot="radio-dot"></span>
        }
      </span>
      <ng-content />
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': "'inline-flex'", '[attr.data-slot]': "'radio'" },
  exportAs: 'hbRadio',
})
export class HbRadioComponent extends HbRadioBase {
  protected readonly circleClasses = computed(() =>
    cn(
      radioVariants({ size: this.effSize(), status: this.effStatus(), focusable: true }),
      this.class(),
    ),
  );
  protected readonly labelClasses = computed(() =>
    cn(
      'relative inline-flex items-center gap-2 text-sm leading-none select-none',
      this.isDisabled() ? 'cursor-not-allowed opacity-70' : 'cursor-pointer',
    ),
  );
}

import { HbRadioCardComponent } from './radio-card.component';
import { HbRadioComponent } from './radio.component';
import { HbRadioGroupComponent } from './radio-group.component';

export const HbRadioImports = [
  HbRadioGroupComponent,
  HbRadioComponent,
  HbRadioCardComponent,
] as const;

import { InjectionToken } from '@angular/core';

import type { HbRadioSize, HbRadioStatus } from './radio.variants';

export interface HbRadioGroupContext {
  readonly value: () => unknown;
  readonly name: () => string;
  readonly disabled: () => boolean;
  readonly invalid: () => boolean;
  readonly size: () => HbRadioSize;
  readonly status: () => HbRadioStatus;
  isSelected(value: unknown): boolean;
  select(value: unknown): void;
  markTouched(): void;
}

export const HB_RADIO_GROUP = new InjectionToken<HbRadioGroupContext>('HB_RADIO_GROUP');

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const radioVariants = cva(
  cn(
    'relative inline-grid shrink-0 place-content-center rounded-full border border-input bg-background shadow-xs transition-shadow',
    '[&>[data-slot=radio-dot]]:rounded-full',
  ),
  {
    variants: {
      size: {
        xs: 'size-3.5 [&>[data-slot=radio-dot]]:size-1.5',
        sm: 'size-4 [&>[data-slot=radio-dot]]:size-2',
        md: 'size-5 [&>[data-slot=radio-dot]]:size-2.5',
        lg: 'size-6 [&>[data-slot=radio-dot]]:size-3',
        xl: 'size-7 [&>[data-slot=radio-dot]]:size-3.5',
      },
      status: {
        default: 'data-[state=checked]:border-primary [&>[data-slot=radio-dot]]:bg-primary',
        error:
          'border-destructive [&>[data-slot=radio-dot]]:bg-destructive',
        success: 'border-success [&>[data-slot=radio-dot]]:bg-success',
        warning: 'border-warning [&>[data-slot=radio-dot]]:bg-warning',
      },
      focusable: {
        true: cn(
          'peer-focus-visible:border-ring peer-focus-visible:ring-[3px] peer-focus-visible:ring-ring/50',
          'peer-disabled:cursor-not-allowed peer-disabled:opacity-50',
          'aria-[invalid=true]:border-destructive aria-[invalid=true]:ring-destructive/20',
        ),
        false: '',
      },
    },
    defaultVariants: { size: 'md', status: 'default', focusable: true },
  },
);

export const radioCardVariants = cva(
  cn(
    'relative flex w-full cursor-pointer items-center gap-3 rounded-md border border-input bg-background p-4 text-left text-sm shadow-xs transition-[color,box-shadow]',
    'has-[:focus-visible]:border-ring has-[:focus-visible]:ring-[3px] has-[:focus-visible]:ring-ring/50',
    'has-[:disabled]:cursor-not-allowed has-[:disabled]:opacity-50',
    'data-[state=checked]:ring-1',
    'aria-[invalid=true]:border-destructive',
  ),
  {
    variants: {
      status: {
        default:
          'data-[state=checked]:border-primary data-[state=checked]:ring-primary data-[state=checked]:bg-primary/5',
        error:
          'data-[state=checked]:border-destructive data-[state=checked]:ring-destructive data-[state=checked]:bg-destructive/5',
        success:
          'data-[state=checked]:border-success data-[state=checked]:ring-success data-[state=checked]:bg-success/5',
        warning:
          'data-[state=checked]:border-warning data-[state=checked]:ring-warning data-[state=checked]:bg-warning/5',
      },
    },
    defaultVariants: { status: 'default' },
  },
);

export type HbRadioSize = NonNullable<VariantProps<typeof radioVariants>['size']>;
export type HbRadioStatus = NonNullable<VariantProps<typeof radioVariants>['status']>;

